Door -> {
  state -> "closed"
  open >- state
  close >- state
  lock >- state
  state -< e {
    open -> state ? {
      "closed" -> "open"
      -> state
    }
    close -> state ? {
      "open" -> "closed"
      -> state
    }
    lock -> state ? {
      "closed" -> "locked"
      -> state
    }
  }
  state >>- display
}
